spec: Add class IsPhoneNumber(DirtyEquals[str]) to dirty_equals/_other.py (needs 'import re' and 'from typing import Optional' added to existing imports, alongside Any/Callable/TypeVar/overload). Implementation:

class IsPhoneNumber(DirtyEquals[str]):
    def __init__(self, country: Optional[str] = None):
        self.country = country.upper() if country else None
        super().__init__(self.country or plain_repr('*'))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False
        cleaned = re.sub(r'[\s\-.()]', '', other)
        if self.country == 'US':
            return self._is_us(cleaned)
        elif self.country == 'GB':
            return self._is_gb(cleaned)
        elif self.country is not None:
            return self._is_generic_international(cleaned)
        else:
            return (
                self._is_us(cleaned)
                or self._is_gb(cleaned)
                or self._is_generic_international(cleaned)
                or bool(re.fullmatch(r'\d{7,15}', cleaned))
            )

    @staticmethod
    def _is_us(number: str) -> bool:
        if number.startswith('+1'):
            return bool(re.fullmatch(r'\d{10}', number[2:]))
        elif number.startswith('+'):
            return False
        else:
            return bool(re.fullmatch(r'\d{10}', number))

    @staticmethod
    def _is_gb(number: str) -> bool:
        if number.startswith('+44'):
            return bool(re.fullmatch(r'\d{9,10}', number[3:]))
        elif number.startswith('+'):
            return False
        else:
            return bool(re.fullmatch(r'0\d{9,10}', number))

    @staticmethod
    def _is_generic_international(number: str) -> bool:
        return bool(re.fullmatch(r'\+\d{7,15}', number))

Behavior notes: strips spaces/dashes/dots/parens before matching (keeps leading plus sign). country arg is an ISO alpha-2 code, case-insensitive input but stored/repr'd uppercase. repr: IsPhoneNumber() renders as IsPhoneNumber(*), IsPhoneNumber('US') renders as IsPhoneNumber('US') (achieved automatically since repr(self.country) or plain_repr('*') is passed to super().__init__, same pattern as IsUUID). Please add a short docstring with a fenced py doctest block (same style as IsUUID's, using title="IsPhoneNumber") showing: generic match via IsPhoneNumber(), US match with and without +1 country code, GB match, and a US number being rejected by IsPhoneNumber('GB'). Place the class near IsUUID/IsJson, order doesn't matter much - after IsJson is fine. Only string inputs accepted; non-strings must return False, not raise.
